	function statusBadgeClass(status: string): string {
		switch (status) {
			case 'open':
				return 'badge-status-open';
			case 'in-progress':
			case 'in_progress':
				return 'badge-status-in-progress';
			case 'closed':
				return 'badge-status-closed';
			case 'blocked':
				return 'badge-status-blocked';
			case 'proposed':
				return 'badge-status-proposed';
			case 'cancelled':
				return 'badge-status-cancelled';
			case 'running':
				return 'badge-status-running';
			case 'completed':
				return 'badge-status-completed';
			case 'failed':
				return 'badge-status-failed';
			default:
				return 'badge-status-neutral';
		}
	}

	function chipClass(active: boolean): string {
		return active
			? 'rounded-sm border px-3 py-1 text-label-caps border-accent-lever bg-accent-lever/10 text-accent-lever dark:border-dark-accent-lever dark:bg-dark-accent-lever/20 dark:text-dark-accent-lever'
