interface BeadEdge {
	node: BeadNode;
	cursor: string;
}

interface PageInfo {
	hasNextPage: boolean;
	endCursor: string | null;
}

interface BeadConnection {
	edges: BeadEdge[];
	pageInfo: PageInfo;
	totalCount: number;
}

interface BeadsResult {
	beadsByProject: BeadConnection;
}

export const load: LayoutLoad = async ({ params, url, fetch }) => {
	const status = url.searchParams.get('status') ?? undefined;
	const label = url.searchParams.get('labels') ?? url.searchParams.get('label') ?? undefined;
	const priority = url.searchParams.get('priority') ?? undefined;
	const sort = url.searchParams.get('sort') === 'priority-desc' ? 'priority-desc' : 'priority-asc';
	const search = url.searchParams.get('q') ?? undefined;

	const client = createClient(fetch as unknown as typeof globalThis.fetch);
	const data = await client.request<BeadsResult>(BEADS_QUERY, {
		projectID: params.projectId,
		first: 10,
		status,
		label,
		search
	});
	return {
		projectId: params.projectId,
		beads: data.beadsByProject,
		activeStatus: status ?? null,
		activeLabel: label ?? null,
		activePriority: priority ?? null,
		activeSort: sort,
		activeSearch: search ?? null
	};
};

import type { PageLoad } from './$types';
import { createClient } from '$lib/gql/client';
import { gql } from 'graphql-request';

const BEAD_QUERY = gql`
	query Bead($id: ID!, $projectID: String!) {
		bead(id: $id) {
			id
			title
			status
			priority
			issueType
			owner
			createdAt
			createdBy
			updatedAt
			labels
			parent
			description
			acceptance
			notes
			dependencies {
				issueId
				dependsOnId
				type
				createdAt
				createdBy
			}
		}
		projectBeads: beadsByProject(projectID: $projectID, first: 500) {
			edges {
				node {
					id
					parent
				}
			}
		}
		beadExecutions: executions(projectId: $projectID, beadId: $id, first: 50) {
			edges {
				node {
					id
					verdict
					harness
					createdAt
					durationMs
					costUsd
				}
			}
			totalCount
		}
		beadRuns: runs(projectID: $projectID, beadID: $id, first: 50) {
			edges {
				node {
					id
					layer
					status
					harness
					startedAt
					durationMs
				}
			}
			totalCount
		}
	}
`;

interface Dependency {
	issueId: string;
	dependsOnId: string;
	type: string;
	createdAt: string | null;
	createdBy: string | null;
}

export interface BeadDetail {
