		params.delete('after');
		searchInput = '';
		const search = params.toString();
		goto(search ? `?${search}` : $page.url.pathname, { replaceState: true });
	}

	async function loadMore() {
		if (!pageInfo.hasNextPage || loadingMore) return;
		loadingMore = true;
		try {
			const client = createClient();
			const result = await client.request<BeadsResult>(BEADS_QUERY, {
				projectID: data.projectId,
				first: 10,
				after: pageInfo.endCursor,
				status: data.activeStatus ?? undefined,
				label: data.activeLabel ?? undefined,
				search: data.activeSearch ?? undefined
			});
			appendedEdges = [...appendedEdges, ...result.beadsByProject.edges];
			appendedPageInfo = result.beadsByProject.pageInfo;
		} finally {
			loadingMore = false;
		}
	}

	function openBead(beadId: string) {
		const p = $page.params as Record<string, string>;
		const searchStr = $page.url.searchParams.toString();
		const beadPath = `/nodes/${p['nodeId']}/projects/${p['projectId']}/beads/${beadId}`;
		goto(searchStr ? `${beadPath}?${searchStr}` : beadPath);
	}

	function statusBadgeClass(status: string): string {
		switch (status) {
			case 'open':
				return 'badge-status-open';
			case 'in-progress':
			case 'in_progress':
				return 'badge-status-in-progress';
			case 'closed':
				return 'badge-status-closed';
			case 'blocked':
				return 'badge-status-blocked';
			case 'proposed':
				return 'badge-status-proposed';
			case 'cancelled':
				return 'badge-status-cancelled';
			case 'running':
				return 'badge-status-running';
			case 'completed':
				return 'badge-status-completed';
			case 'failed':
				return 'badge-status-failed';
			default:
				return 'badge-status-neutral';
		}
	}

	function chipClass(active: boolean): string {
		return active
			? 'rounded-sm border px-3 py-1 text-label-caps border-accent-lever bg-accent-lever/10 text-accent-lever dark:border-dark-accent-lever dark:bg-dark-accent-lever/20 dark:text-dark-accent-lever'
			: 'rounded-sm border px-3 py-1 text-label-caps border-border-line bg-bg-elevated text-fg-ink hover:border-fg-muted hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface';
	}

	function priorityLabel(priority: number): string {
		return `P${priority}`;
	}

	function priorityClass(priority: number): string {
		return `text-priority-p${priority}`;
	}
</script>

